def art(slug, title, desc, tag, tc, h1, lead, secs, faqs, rel):
    out = os.path.join(BASE, "blog", slug)
    os.makedirs(out, exist_ok=True)
    fpath = os.path.join(out, "index.html")
    ld_article = {"@type": "Article", "headline": title, "description": desc,
                  "author": {"@type": "Organization", "name": "ProdutoVivo"},
                  "publisher": {"@type": "Organization", "name": "ProdutoVivo", "url": "https://produtovivo.com.br"}}
    ld_faq = {"@type": "FAQPage", "mainEntity": [
        {"@type": "Question", "name": q, "acceptedAnswer": {"@type": "Answer", "text": a}}
        for q, a in faqs]}
    ld = json.dumps({"@context": "https://schema.org", "@graph": [ld_article, ld_faq]}, ensure_ascii=False)
    secs_html = "".join(f"<h2>{s['h']}</h2><p>{s['p']}</p>" for s in secs)
    faqs_html = "".join(f"<details><summary>{q}</summary><p>{a}</p></details>" for q, a in faqs)
    rel_html = "".join(f'<li><a href="/blog/{r}/">{r.replace("-", " ").title()}</a></li>' for r in rel)
    url = f"https://produtovivo.com.br/blog/{slug}/"
    html = f"""<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>{title}</title>
<meta name="description" content="{desc}">
<link rel="canonical" href="{url}">
<script type="application/ld+json">{ld}</script>
<style>{CSS}</style>
<!-- Meta Pixel -->
<script>!function(f,b,e,v,n,t,s){{if(f.fbq)return;n=f.fbq=function(){{n.callMethod?n.callMethod.apply(n,arguments):n.queue.push(arguments)}};if(!f._fbq)f._fbq=n;n.push=n;n.loaded=!0;n.version='2.0';n.queue=[];t=b.createElement(e);t.async=!0;t.src=v;s=b.getElementsByTagName(e)[0];s.parentNode.insertBefore(t,s)}}(window,document,'script','https://connect.facebook.net/en_US/fbevents.js');fbq('init','{PIXEL}');fbq('track','PageView');</script>
</head>
<body>
<nav class="nav"><a href="/">ProdutoVivo</a><a href="/#comprar">Quero o Guia R$37</a></nav>
<section class="hero">
<h1>{h1}</h1>
<p class="lead">{lead}</p>
<a class="cta-btn" href="/#comprar">Quero Criar Meu Infoproduto</a>
</section>
<div class="content">{secs_html}</div>
<section class="faq"><h2>Perguntas Frequentes sobre {tc}</h2>{faqs_html}</section>
<div class="cta-box">
<h2>Crie Seu Infoproduto com o Guia ProdutoVivo</h2>
<p>Aprenda a transformar seu conhecimento em um infoproduto digital que vende — passo a passo, com IA e sem precisar de equipe técnica.</p>
<a class="cta-btn" href="/#comprar">Começar por R$37</a>
</div>
<div class="related"><h2>Artigos Relacionados</h2><ul>{rel_html}</ul></div>
<footer>© 2025 ProdutoVivo · <a href="/privacidade.html" style="color:#cce">Privacidade</a></footer>
</body>
</html>"""
    with open(fpath, "w", encoding="utf-8") as f:
        f.write(html)
    print(f"  OK {slug}")

